var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"업데이트 예정일은 미정입니다. 저희 측에서도 전혀 전달받지 못한 사항이라…….","JPN":"アップデート予定日は未定です。私たちにも共有されてなかった内容で……","ENG":"The schedule for the update has not been determined yet. This is something we're also hearing for the first time...","TWN":"預定更新日期尚未確定，我們這邊也完全沒有收到相關通知……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아, 아뇨. 카운터즈 레거시에 접속할 수 있다고 해서, 일반 자녀분이 카운터 아카데미에 입학할 수는 없습니다.","JPN":"い、いえ。カウンターズ・レガシーにアクセスできるというだけで、一般のお子さんがカウンターアカデミーに入学することはできません。","ENG":"Oh, no. Just because one can access Counters Legacy doesn't mean that non-Counters can enroll in the Counter Academy.","TWN":"不是的。即使可以登入制裁者的遺產，普通人也不能進入制裁者學院。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"휴…… 방송 이후로 전화가 끝도 없이 오네.","JPN":"ふう……配信以降、電話が鳴りやまないわね。","ENG":"*Sigh* The phone's been ringing nonstop since that livestream.","TWN":"呼……直播結束後電話就沒停過。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"보라는 괜찮아? 회사엔 별일 없는 거야?","JPN":"シホちゃんは大丈夫？　会社では変わったことは起きてない？","ENG":"How are you doing, Bora? Is everything okay at work?","TWN":"寶拉還好嗎？公司沒事吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"계획하고 있던 건 맞아…….","JPN":"計画していたのは確か……","ENG":"It was something that was planned...","TWN":"確實是計畫好的……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"일반인…… 노멀 플레이어의 유입.","JPN":"一般人……ノーマルプレイヤーを招き入れること。","ENG":"Non-Counters... Normal players getting access.","TWN":"普通人……普通玩家的湧入。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"시기상조…… 지금은.","JPN":"でも……まだ時期尚早。","ENG":"But right now... it's too early.","TWN":"現在……還為時尚早。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"선배! 방송 보셨죠? 오버로드는 바로 다음 주부터 투입될 예정이에요!","JPN":"先輩！　配信見てくれました？　オーバーロードは来週から導入される予定です！","ENG":"Bora! Did you see the livestream? Overlord is going to be implemented next week!","TWN":"前輩！你看直播了嗎？超載計畫將在下週開始執行！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그리고 있죠! 저 드디어 개발 총괄 자리에 올랐어요!","JPN":"あとですね、私ついに開発総括になりました！","ENG":"Also! I've finally become the chief of development!","TWN":"還有！我終於升任開發總監了！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"……가람아.","JPN":"……ヒカリ。","ENG":"...Garam.","TWN":"……嘉蘭。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"왜 말 안 했어……? 오버로드 투입.","JPN":"なんで言ってくれなかった……？　オーバーロードの件。","ENG":"Why didn't you tell me... about Overlord?","TWN":"為什麼不告訴我……？超載的投入。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"선배를 깜짝 놀라게 해 드리고 싶었으니까요!","JPN":"先輩をびっくりさせたかったからです！","ENG":"Because I wanted it to be a surprise!","TWN":"因為我想給前輩一個驚喜！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L22_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"제 힘으로도 충분히 성공한다는 걸 보여주고 싶었어요!","JPN":"私の力だけでも十分できるって、見せてあげたかったんです！","ENG":"I wanted to show you that I could do it on my own!","TWN":"我想證明光靠我的力量也能成功！"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"장난칠 기분 아냐……. 지금.","JPN":"ふざけてる気分じゃない……今は。","ENG":"Now's not the time... for jokes.","TWN":"現在沒心情開玩笑……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"……네?","JPN":"……え？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"진행하기로 했잖아……. 충분히 검증된 뒤에.","JPN":"進めるつもりだった……十分検証が終わった後。","ENG":"We decided to proceed... after it was thoroughly tested.","TWN":"不是說好要進行的嗎……在充分測試之後。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"너무…… 무책임했어.","JPN":"あまりにも……無責任すぎる。","ENG":"You were... irresponsible.","TWN":"太……不負責任了。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"무책임하다고요……?","JPN":"無責任って……？","ENG":"Irresponsible...?","TWN":"不負責任……？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그, 그렇지 않아요! 관리국과 협의하고, 안정성을 검증한 것도 전부 저였는데……","JPN":"ち、違います！　管理局と協議して、安定性を検証したのも全部私で……","ENG":"N-no! I did everything, from discussing it with the Administration to testing its safety...","TWN":"不，不是這樣的！和管理局協商，測試穩定性都是我做的……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"선배도 독단적으로 나이트를 사용하셨잖아요.","JPN":"先輩も独断でナイトを使ったじゃないですか。","ENG":"Besides, you used Knight without telling us, too.","TWN":"前輩也擅自使用了騎士不是嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"전…… 왜 안 되는 건가요……?","JPN":"私は……なんでダメなんですか……？","ENG":"So, why... can't I do the same...?","TWN":"我……為什麼不行……？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"전 그저 이 프로젝트를 성공시켜서, 선배를 깜짝 놀라게 해 드리고 싶었어요.","JPN":"私はただ、このプロジェクトを成功させて、先輩をびっくりさせたかったんです。","ENG":"I just wanted to make this project a success and surprise you.","TWN":"我只是想讓這個項目成功，讓前輩大吃一驚。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"선배를…… 정말 동경하니까.","JPN":"先輩に……憧れているから。","ENG":"Because... you're my role model.","TWN":"因為……真的很仰慕前輩。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"막아 세우려는 게 아냐…… 아직은 이를 뿐.","JPN":"止めようとしてるわけじゃない……まだ早いだけ。","ENG":"I'm not trying to stop you... It's just too early.","TWN":"不是想阻止你……只是現在還不到時候。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"철회…… 하자.","JPN":"撤回……しよ。","ENG":"Let's... take it back.","TWN":"撤回……吧。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"……그럴 순 없어요. 전 이거 반드시 성공시키고 싶어요.","JPN":"……それはできません。私はこれを絶対成功させたいです。","ENG":"...I can't do that. I want to make this work, no matter what.","TWN":"……那樣不行。我一定要成功完成這件事。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"그럼 내가 할 게…… 오버로드의 관리.","JPN":"じゃ、私がやる……オーバーロードの管理。","ENG":"Then I'll... manage Overlord.","TWN":"那讓我來……管理超載。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"벅찰 테니까……. 혼자선.","JPN":"手に負えないだろうから……1人では。","ENG":"It'll be overwhelming... to do it by yourself.","TWN":"會很吃力的……一個人。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"……아뇨. 죄송하지만 선배의 도움은 받지 않을게요.","JPN":"……いいえ、申し訳ありませんが先輩の助けは要りません。","ENG":"...No. I'm sorry, but I don't want your help.","TWN":"……不。抱歉，我不會接受前輩的幫助。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"저도 선배만큼 할 수 있다는 걸 보여드리겠어요.","JPN":"私も先輩と同じぐらいできるって、証明してみせます。","ENG":"I need to prove that I can do as much as you.","TWN":"我會向你證明，我也能像前輩一樣出色。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L48_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};